import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"业","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/业.md","filePath":"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/业.md"}'),o={name:"4.资源分区/1.血统与训练/4.综合类/千禧骑士/武器/业.md"};function d(p,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"业",tabindex:"-1"},[n("业 "),r("a",{class:"header-anchor",href:"#业","aria-label":'Permalink to "业"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002")])])],-1),s('<h1 id="业-1" tabindex="-1">业 <a class="header-anchor" href="#业-1" aria-label="Permalink to &quot;业&quot;">​</a></h1><p>业<br> D+500<br> 特异本质<br> 武器伤害6L 高速1<br> 这是一柄握柄上刻着无数乱樱的武士刀，刀身上刻着随着持有者的行动而逐渐亮起的荧光铭文，还会随着与接触物或交击物材质不同发出不同的乐音<br> 使用者的举手投足都如同绝美的舞蹈，一呼一吸之间便可以让敌人心甘情愿的献上头颅<br> 你的所有动作都将具有美感，这种美感的观感将由你来决定，在你进行任何移动检定时，都先进行一次风度+表达+专业：舞蹈的检定，并将此次检定的成功数加在此次移动的距离上，视为可以额外移动的距离<br> 从此等级开始，业的所有攻击都视为应用了一种业独有的攻击招式，这个招式被称为乱花式，使用乱花式是一个标准动作，被攻击的敌人会发觉阵阵乱花飘过，迷花双眼。其会受到仅生效一轮的等同于千禧骑士武器选择的属性附加*1点的攻击检定减值，每使用业在战斗场景中对敌人进行一次攻击，都会致使刀身正面的一道银色铭文亮起</p><p>业无需主动升级，只需购买对应等级的业能够使用的招式便会自动升级，同时，每个等级的招式将不会提供属性点，而是提供标注的武器伤害，所有获得的业对应的非乱花式招式在使用一次后都会使此前积攒的银色铭文黯淡<br> 对于每个更高等级的招式而言，每个除乱花式外的低等级的招式在战斗场景使用对敌人进行攻击时都会在背面亮起X道黑色铭文（C1B2A4），更高等级的招式在使用时也可以以黑色铭文为使用基础，在使用后同样会黯淡下来</p><p>迷花式<br> C+1000<br> 武器伤害14L<br> 使用前提：至少亮起三道银色铭文<br> 使用迷花式是一个标准动作，以下同理。使用迷花式时会以自身为中心，在15米半径范围内刮起一阵乱风，卷起无数樱花迷惑众人的视野，在此范围内所有敌人均会受到这次攻击，同时在本轮中，由于乱花的笼盖，你将遁入飘飞的花絮中，视为拥有D级反侦察效果<br> 梦切：在使用迷花式时，每多拥有一道亮起的银色铭文，就会再使此范围内所有敌人降低2点意志豁免持续一轮，并使那些额外的铭文黯淡</p><p>谢花式<br> B+2000<br> 武器伤害21L<br> 使用前提：至少亮起三道银色铭文或一道黑色铭文<br> 使用谢花式是一个标准动作，将会对被攻击的目标施以枭首攻击，这次攻击将以对方的头部为目标，并造成等同于伤害出目的肢体妨碍，对方使用标准豁免抵抗这些肢体妨碍，在使用时每使用了一道银色铭文，就会降低其1点强韧豁免以应对这次攻击；如果使用的是黑色铭文，则会降低4点。若这次攻击成功将其枭首（即被攻击者头部肢体妨碍毁灭），还会立即进入A级别、特异本质的反侦测等级中，持续一个场景<br> 幻切：在使用谢花式时，每多拥有一道亮起的银色铭文，就会再使被攻击者降低1点强韧豁免以应对这次攻击，如果拥有的是黑色铭文，则会降低4点，并使那些额外的铭文黯淡下来</p><p>落花式<br> A+4000<br> 武器伤害34L<br> 使用前提：至少亮起四道银色铭文或一道黑色铭文<br> 落花式将会对以自身为中心15米范围内所有敌人造成一次攻击，这次攻击使用意志豁免进行减免，受到伤害的目标需要进行强韧豁免伤害值，失败则还会令这些敌人陷入五感剥夺的状态之中（触觉、听觉、视觉、味觉、嗅觉），这视为一个A级环境来源的负面效果。一轮后，处于这一范围内的所有单位会进入S级、幻象来源的困难地形之中，在离开此范围前，无法使用自身A级及以下的所有强化，这是一个A级幻象来源的支配效果。这些效果将持续一轮<br> 冥切：在使用落花式时，每多拥有一道亮起的银色铭文，就会再使作用范围扩大200米；每多拥有一道亮起的黑色铭文，就会再使作用范围扩大800米，并使那些额外的铭文黯淡下来</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
